CREATE TABLE "TeracParticipant" ("id" TEXT NOT NULL, "teracSubmissionId" TEXT, "startedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "completedAt" TIMESTAMP(3), "collectionCompletedAt" TIMESTAMP(3), "labelCompletedAt" TIMESTAMP(3), "wave" TEXT NOT NULL DEFAULT 'collect', "status" TEXT NOT NULL DEFAULT 'started', CONSTRAINT "TeracParticipant_pkey" PRIMARY KEY ("id"));
CREATE TABLE "CollectedMessage" ("id" TEXT NOT NULL, "submittedByParticipantId" TEXT NOT NULL, "sanitizedText" TEXT NOT NULL, "inputMethod" TEXT NOT NULL DEFAULT 'text_paste', "sanitizedSubject" TEXT, "sanitizedBody" TEXT, "source" TEXT NOT NULL, "initialUserBelief" TEXT NOT NULL, "shortContext" TEXT, "fromDomain" TEXT, "replyToDomain" TEXT, "returnPathDomain" TEXT, "fromReplyToMismatch" BOOLEAN, "linkFeatures" TEXT, "authSummary" TEXT, "hasAttachments" BOOLEAN NOT NULL DEFAULT false, "attachmentExtensions" TEXT, "attachmentsStripped" BOOLEAN NOT NULL DEFAULT true, "emlParsedClientSide" BOOLEAN, "isSyntheticTestFixture" BOOLEAN NOT NULL DEFAULT false, "parserWarnings" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "CollectedMessage_pkey" PRIMARY KEY ("id"));
CREATE TABLE "MessageLabel" ("id" TEXT NOT NULL, "messageId" TEXT NOT NULL, "labeledByParticipantId" TEXT NOT NULL, "riskLevel" TEXT NOT NULL, "scamType" TEXT NOT NULL, "redFlags" TEXT NOT NULL, "recommendedAction" TEXT NOT NULL, "plainEnglishWarning" TEXT NOT NULL, "confidence" INTEGER NOT NULL, "rationale" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "MessageLabel_pkey" PRIMARY KEY ("id"));
CREATE TABLE "LabelAssignment" ("id" TEXT NOT NULL, "participantId" TEXT NOT NULL, "messageId" TEXT NOT NULL, "position" INTEGER NOT NULL, "assignedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "completedAt" TIMESTAMP(3), CONSTRAINT "LabelAssignment_pkey" PRIMARY KEY ("id"));
CREATE TABLE "QualityFlag" ("id" TEXT NOT NULL, "targetType" TEXT NOT NULL, "targetId" TEXT NOT NULL, "reason" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "QualityFlag_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "TeracParticipant_teracSubmissionId_key" ON "TeracParticipant"("teracSubmissionId");
CREATE UNIQUE INDEX "MessageLabel_messageId_labeledByParticipantId_key" ON "MessageLabel"("messageId", "labeledByParticipantId");
CREATE UNIQUE INDEX "LabelAssignment_participantId_messageId_key" ON "LabelAssignment"("participantId", "messageId");
CREATE UNIQUE INDEX "LabelAssignment_participantId_position_key" ON "LabelAssignment"("participantId", "position");
ALTER TABLE "CollectedMessage" ADD CONSTRAINT "CollectedMessage_submittedByParticipantId_fkey" FOREIGN KEY ("submittedByParticipantId") REFERENCES "TeracParticipant"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "MessageLabel" ADD CONSTRAINT "MessageLabel_messageId_fkey" FOREIGN KEY ("messageId") REFERENCES "CollectedMessage"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "MessageLabel" ADD CONSTRAINT "MessageLabel_labeledByParticipantId_fkey" FOREIGN KEY ("labeledByParticipantId") REFERENCES "TeracParticipant"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "LabelAssignment" ADD CONSTRAINT "LabelAssignment_participantId_fkey" FOREIGN KEY ("participantId") REFERENCES "TeracParticipant"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "LabelAssignment" ADD CONSTRAINT "LabelAssignment_messageId_fkey" FOREIGN KEY ("messageId") REFERENCES "CollectedMessage"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
